{
  "mode": "io",
  "tests": [
    {
      "name": "valid_user_login",
      "input": "{\"username\": \"testuser\", \"password\": \"securepassword\"}",
      "output": "{\"status\": \"success\", \"token\": \"abc123\"}",
      "notes": "Validates successful user authentication."
    },
    {
      "name": "invalid_user_login",
      "input": "{\"username\": \"wronguser\", \"password\": \"wrongpassword\"}",
      "output": "{\"status\": \"error\", \"message\": \"Invalid credentials\"}",
      "notes": "Tests response for invalid login credentials."
    },
    {
      "name": "upload_valid_asset",
      "input": "{\"project_id\": 1, \"file\": \"valid_image.png\"}",
      "output": "{\"status\": \"success\", \"asset_id\": 101}",
      "notes": "Checks if a valid asset can be uploaded successfully."
    },
    {
      "name": "upload_invalid_asset_type",
      "input": "{\"project_id\": 1, \"file\": \"invalid_file.txt\"}",
      "output": "{\"status\": \"error\", \"message\": \"Unsupported file type\"}",
      "notes": "Ensures that uploading an invalid file type is rejected."
    },
    {
      "name": "generate_ai_asset",
      "input": "{\"asset_id\": 101, \"strategy\": \"face-centric crop\"}",
      "output": "{\"status\": \"success\", \"generated_asset_id\": 201}",
      "notes": "Validates the generation of an AI-processed asset."
    },
    {
      "name": "generate_ai_asset_invalid_strategy",
      "input": "{\"asset_id\": 101, \"strategy\": \"unknown strategy\"}",
      "output": "{\"status\": \"error\", \"message\": \"Invalid AI strategy\"}",
      "notes": "Tests response for an invalid AI strategy."
    },
    {
      "name": "content_moderation_nsfw_check",
      "input": "{\"file\": \"nsfw_image.png\"}",
      "output": "{\"status\": \"error\", \"message\": \"Content flagged as NSFW\"}",
      "notes": "Checks if NSFW content is correctly flagged."
    },
    {
      "name": "content_moderation_file_size_check",
      "input": "{\"file\": \"large_image.png\", \"size\": 5000000}",
      "output": "{\"status\": \"error\", \"message\": \"File size exceeds limit\"}",
      "notes": "Ensures that files exceeding size limits are rejected."
    }
  ],
  "assumptions": "All inputs are properly formatted JSON strings.",
  "notes": "Tests cover user authentication, asset management, AI generation, and content moderation."
}
